def main():
    if '--timeout' in sys.argv:
        timeout = int(sys.argv[sys.argv.index('--timeout')+1])
        if timeout < 30:
            raise ValueError('Timeout must be at least 30 seconds')
        jira_timeout = timeout
    else:
        jira_timeout = 30
    from urllib.parse import urlparse
    try:
        url = urlparse(sys.argv[1])
    except ValueError:
        raise ValueError('Invalid URL')

    if jira_timeout < 30:
        raise ValueError('Timeout must be at least 30 seconds')

    # Ensure we use a reasonable timeout for Jira
    if jira_timeout < 30:
        jira_timeout = 30

    # Set the curl timeout
    import urllib.request
    try:
        urllib.request.urlretrieve(url.path, url.path + f'/jira-{jira_timeout}.zip', file_url=f'jira-{jira_timeout}.zip')
    except Exception as e:
        raise ValueError(f'Failed to download: {e}')

if __name__ == '__main__':
    main()
